INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-04820', 'social-worker', 'social-worker-moex-108-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「人治的意思很簡單，即『我覺得怎麼樣好，就那樣做』，在決策的時候完全是以 個人的想法及情緒為主，沒有準則。這麼一來，當一件事情發生的時候，夥伴們是 很難知道主管會如何處理？進而造成大家猜測、猜疑、猜忌的心理，對主管的話充 滿不信任，夥伴們之間也互相提防，對組織來說，絕對是極大的傷害。為了避免這 樣的情形，不管你的單位多小，在決定事情的時候，一定要將『為什麼做這樣的決 定』的理由說清楚，講明白，讓大家知道你是一位誠實、有原則、為大家著想的主 管，進而增加組織人員的定著率。」 根據上文，作者的想法為：', '["凡事聽從上級指令不節外生枝就是「人治」", "有原則的主管比人治的主管更能使員工信服", "員工在做事之前應該要問清楚為什麼要這樣做", "在人治公司裡若能潔身自愛就可以得到主管信任"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "3f86db5a23ec", "answer_pdf_sha1": "60dbb347d2af", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04821', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'essay', '林姓社會工作者（以下簡稱林社工）在機構任職多年，與機構主任私交很
好。李小姐是林社工的鄰居和同學，彼此關係熟識，常相互串門子，且彼
此有金錢往來。李小姐母親（以下稱李媽媽）自去年起，在林社工任職的
養護機構接受日間照顧服務。一年下來，李媽媽習慣了機構的生活，林社
工也與她建立信任關係，常用小名稱呼林社工，並常說林社工就像自己的
女兒一樣。李小姐計劃今年暑假出國，林社工建議可以讓李媽媽短期安置
到另一家全日照顧之養護中心。但是李小姐表示媽媽可能無法適應，希望
林社工晚上到家裡幫忙照顧。林社工在難以拒絕請求下答應。事後機構同
事王社工得知林社工晚間到府提供照顧服務，其實是私下收了李小姐的金
錢，但對外說這是朋友之間的幫忙，是私事。請問王社工應有何倫理和文
化考量？應如何做倫理判斷和決定是否舉報？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "03b97727a646", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": "一", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04822', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'essay', '依據家庭生命週期與家庭系統理論，一對育有 3歲及 8歲子女的身心障
礙父母可能面對那些家庭生活困境？社會工作者應如何介入及處遇？
（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "03b97727a646", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04823', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '臺灣社會工作專業發展過程有很多有意義的首次，下列何者錯誤？', '["臺灣世界展望會是臺灣第一個聘用社會工作員的民間社福單位", "臺灣最早聘用社會工作員的是醫院", "臺灣社會工作員制度法制化文字出現於1976年「中華民國臺灣經濟建設六年計畫」", "1971年政府通過設置社會工作員實驗計畫，聘用10名社會工作員，負責平價住宅業務"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "03b97727a646", "answer_pdf_sha1": "c16ada950660", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04824', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作師經完成專科社會工作師訓練，並經中央主管機關甄審合格者，得請領專科社會工作師 證書，下列何者不是目前臺灣專科社會工作師領域之分類？', '["心理衛生", "兒童、少年、婦女及家庭", "原住民", "身心障礙"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "03b97727a646", "answer_pdf_sha1": "c16ada950660", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04825', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '學者Bernard指出具有「復原力」的兒童擁有四種能力，下列何者錯誤？', '["社會能力", "問題解決能力", "依賴能力", "對未來具有目標感"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "03b97727a646", "answer_pdf_sha1": "c16ada950660", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04826', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列關於社會工作意涵的敘述，何者正確？', '["社會工作者尊重服務對象的自我抉擇，且這個過程中並不會與社會工作者的專家角色產生矛盾", "社會工作與其他專業最大區別在於社會工作服務協助的重點同時兼顧個人與環境，以及兩者之 間的互動", "社會工作在致力協助人們，以及改善社會的各種做法時，並不會與其他專業重疊", "社會工作主要是待在辦公室內等待服務對象前來尋求協助，並不需要在辦公室外的各種場所執 行業務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "03b97727a646", "answer_pdf_sha1": "c16ada950660", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04827', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在社會工作實務中，社會工作者可發揮之功能相當多，下列何者主要是協助案主發展資源的工作？', '["慢性精神疾病患者參與職能訓練工作坊", "自閉症學童參與語言治療", "即將結婚的伴侶參加婚前教育和成長團體", "憂鬱症患者擴展了社會網絡"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "03b97727a646", "answer_pdf_sha1": "c16ada950660", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04828', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在 1930 年代末，社會工作的三種基本工作方法成型，請問是那三種工作方法？①個案工作', '["團體工作", "社區工作", "社會工作管理", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "03b97727a646", "answer_pdf_sha1": "c16ada950660", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 6, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04829', 'social-worker', 'social-worker-moex-108-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '依據貝斯提克（Biestek, 1967），下列敘述何者正確？①社會工作是一門藝術，理論未必需要作', '["社會工作應以人類關係的知識與技術為基礎", "社會工作者應與服務對象建 立個別化的關係", "社會工作者不應該洩漏從專業關係中所獲得的案主資訊", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:28+00:00", "source_pdf_sha1": "03b97727a646", "answer_pdf_sha1": "c16ada950660", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "107", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
